import { processImages } from './imageProcessor';
import { generateOutputs } from './outputGenerator';
import { aggregateTokens } from './tokenAggregator';
import { validateResults } from './validator';

/**
 * Main Flow: UI Token Extraction Pipeline
 * 
 * Phase 1: Image Processing (Parallel)
 * Phase 2: Token Aggregation (Deduplication + Validation)
 * Phase 3: Multi-format Output Generation
 */
async function main() {
  console.log('🚀 Starting UI Token Extraction Flow v2.0');
  console.log('━'.repeat(50));

  // Phase 1: Process all images in parallel
  console.log('\n📸 Phase 1: Processing images...');
  const imageResults = await processImages();
  console.log(`✅ Processed ${imageResults.length} images`);

  // Phase 2: Aggregate and deduplicate tokens
  console.log('\n🔧 Phase 2: Aggregating design tokens...');
  const designSystem = aggregateTokens(imageResults);
  console.log('✅ Design system aggregated');

  // Phase 2.5: Validate tokens
  console.log('\n✓ Validating tokens...');
  const validation = validateResults(designSystem, imageResults);
  if (!validation.isValid) {
    console.warn('⚠️  Validation warnings:', validation.warnings);
  }

  // Phase 3: Generate all outputs
  console.log('\n📝 Phase 3: Generating outputs...');
  const outputs = await generateOutputs(designSystem, imageResults);

  console.log('\n━'.repeat(50));
  console.log('✅ COMPLETE! Generated files:');
  outputs.forEach(file => console.log(`   📄 ${file.name}`));
  console.log('\n💾 All files saved to: /output/');

  return {
    success: true,
    imagesProcessed: imageResults.length,
    tokensExtracted: designSystem.stats,
    filesGenerated: outputs.map(f => f.name)
  };
}

main().catch(error => {
  console.error('❌ Flow failed:', error);
  process.exit(1);
});

