function inferScreenMetadata(filename: string, tokens: any, components: any[]): any {
  const type = filename.includes('modal') ? 'modal' 
    : filename.includes('onboarding') ? 'onboarding'
    : filename.includes('component') ? 'component'
    : filename.includes('auth') ? 'auth'
    : filename.includes('destination') ? 'detail'
    : 'list';

  return {
    type,
    primaryIntent: inferPrimaryIntent(filename, type),
    userFlow: inferUserFlow(filename)
  };
}

function inferPrimaryIntent(filename: string, type: string): string {
  // Logic to infer what the user is trying to do on this screen
  return 'Unknown';
