function generateImageId(filename: string): string {
  return filename.replace('.png', '').replace(/[^a-z0-9]/g, '-');
}

function inferScreenName(filename: string): string {
  return filename
    .replace('.png', '')
    .split('-')
    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}

