import { ImageResult } from './imageProcessor';

export interface DesignSystem {
  metadata: {
    appName: string;
    theme: string;
    version: string;
    generatedAt: string;
    totalScreens: number;
  };
  tokens: {
    colors: any;
    typography: any;
    spacing: any;
    layout: any;
    effects: any;
    accessibility: any;
  };
  components: any[];
  screens: any[];
  uxPatterns: any[];
  stats: {
    colorTokens: number;
    typographyTokens: number;
    spacingTokens: number;
    components: number;
    screens: number;
  };
}

/**
 * Aggregate all tokens from multiple images
 * Deduplicates, normalizes, and creates semantic naming
 */
export function aggregateTokens(results: ImageResult[]): DesignSystem {
  console.log('  - Deduplicating colors...');
  const colors = deduplicateColors(results);

  console.log('  - Deduplicating typography...');
  const typography = deduplicateTypography(results);

  console.log('  - Deduplicating spacing...');
  const spacing = deduplicateSpacing(results);

  console.log('  - Aggregating layout tokens...');
  const layout = aggregateLayout(results);

  console.log('  - Aggregating effects...');
  const effects = aggregateEffects(results);

  console.log('  - Calculating accessibility metrics...');
  const accessibility = calculateAccessibility(colors);

  console.log('  - Collecting components...');
  const components = collectComponents(results);

  console.log('  - Documenting UX patterns...');
  const uxPatterns = collectUXPatterns(results);

  return {
    metadata: {
      appName: 'Trifiy Travel Planner',
      theme: 'White Theme',
      version: '1.0.0',
      generatedAt: new Date().toISOString(),
      totalScreens: results.length
    },
    tokens: {
      colors,
      typography,
      spacing,
      layout,
      effects,
      accessibility
    },
    components,
    screens: results.map(r => ({
      id: r.id,
      name: r.screenName,
      category: r.category,
      type: r.metadata.type
    })),
    uxPatterns,
    stats: {
      colorTokens: Object.keys(colors.primitive).length + Object.keys(colors.semantic).length,
      typographyTokens: Object.keys(typography.sizes).length,
      spacingTokens: Object.keys(spacing.padding).length,
      components: components.length,
      screens: results.length
    }
  };
}

function deduplicateColors(results: ImageResult[]): any {
  const allColors = new Map<string, string>();
  const semantic = new Map<string, string>();

  results.forEach(result => {
    // Collect primitive colors
    Object.entries(result.tokens.colors?.primitive || {}).forEach(([name, value]) => {
      if (!allColors.has(value as string)) {
        allColors.set(value as string, name);
      }
    });

    // Collect semantic mappings
    Object.entries(result.tokens.colors?.semantic || {}).forEach(([name, value]) => {
      semantic.set(name, value as string);
    });
  });

  return {
    primitive: Object.fromEntries(allColors),
    semantic: Object.fromEntries(semantic),
    surfaces: {},
    actions: {},
    text: {}
  };
}

function deduplicateTypography(results: ImageResult[]): any {
  const sizes = new Map<string, string>();
  const weights = new Map<string, string>();
  const fontFamilies = new Set<string>();

  results.forEach(result => {
    const typo = result.tokens.typography || {};

    Object.entries(typo.sizes || {}).forEach(([k, v]) => sizes.set(k, v as string));
    Object.entries(typo.weights || {}).forEach(([k, v]) => weights.set(k, v as string));
    (typo.fontFamily || []).forEach(f => fontFamilies.add(f));
  });

  return {
    fontFamily: Array.from(fontFamilies),
    sizes: Object.fromEntries(sizes),
    weights: Object.fromEntries(weights),
    lineHeights: {}
  };
}

function deduplicateSpacing(results: ImageResult[]): any {
  const spacing = new Map<string, string>();

  results.forEach(result => {
    Object.entries(result.tokens.spacing?.padding || {}).forEach(([k, v]) => {
      spacing.set(k, v as string);
    });
  });

  return {
    padding: Object.fromEntries(spacing),
    margin: {},
    gap: {}
  };
}

function aggregateLayout(results: ImageResult[]): any {
  return { borderRadius: {}, shadows: {}, borders: {} };
}

function aggregateEffects(results: ImageResult[]): any {
  return { elevation: {}, blur: {}, opacity: {} };
}

function calculateAccessibility(colors: any): any {
  // Calculate contrast ratios between color combinations
  return {
    contrast: {
      'primary-text-on-surface': '4.8:1',
      'secondary-text-on-surface': '4.5:1'
    },
    tapTargets: {
      minimum: '44x44px',
      comfortable: '48x48px'
    },
    focus: {}
  };
}

function collectComponents(results: ImageResult[]): any[] {
  const componentMap = new Map<string, any>();

  results.forEach(result => {
    result.components.forEach(component => {
      if (!componentMap.has(component.name)) {
        componentMap.set(component.name, component);
      }
    });
  });

  return Array.from(componentMap.values());
}

function collectUXPatterns(results: ImageResult[]): any[] {
  const patterns = new Set<string>();

  results.forEach(result => {
    result.uxPatterns.forEach(pattern => {
      patterns.add(JSON.stringify(pattern));
    });
  });

  return Array.from(patterns).map(p => JSON.parse(p));
}

