export interface OutputFile {
  name: string;
  content: string;
  type: 'markdown' | 'json' | 'css' | 'javascript';
}

/**
 * Generate all output files in multiple formats
 */
export async function generateOutputs(
  designSystem: DesignSystem,
  imageResults: ImageResult[]
): Promise<OutputFile[]> {
  const outputs: OutputFile[] = [];

  console.log('  - Generating ui-style-guide.md...');
  outputs.push(generateStyleGuide(designSystem));

  console.log('  - Generating ui-components.md...');
  outputs.push(generateComponentsDoc(designSystem));

  console.log('  - Generating screen-reference.md...');
  outputs.push(generateScreenReference(imageResults));

  console.log('  - Generating accessibility-tokens.md...');
  outputs.push(generateAccessibilityDoc(designSystem));

  console.log('  - Generating progress-tracker.md...');
  outputs.push(generateProgressTracker(imageResults));

  console.log('  - Generating design-tokens.json...');
  outputs.push(generateTokensJSON(designSystem));

  console.log('  - Generating tokens.css (CSS Variables)...');
  outputs.push(generateCSSVariables(designSystem));

  console.log('  - Generating tailwind.config.js...');
  outputs.push(generateTailwindConfig(designSystem));

  // Write all files
  await writeOutputFiles(outputs);

  return outputs;
}

function generateStyleGuide(ds: DesignSystem): OutputFile {
