> Generated: ${new Date(ds.metadata.generatedAt).toLocaleString()}
> Theme: ${ds.metadata.theme}
> Total Screens: ${ds.metadata.totalScreens}

## Overview

Complete design system documentation for ${ds.metadata.appName}.

## Color System

### Primitive Colors

${Object.entries(ds.tokens.colors.primitive)
  .map(([name, value]) => `- **${name}** → \`${value}\``)
  .join('\n')}

### Semantic Colors

${Object.entries(ds.tokens.colors.semantic)
  .map(([name, value]) => `- **${name}** → \`${value}\``)
  .join('\n')}

## Typography

### Font Families

${ds.tokens.typography.fontFamily.map(f => `- ${f}`).join('\n')}

### Font Sizes

${Object.entries(ds.tokens.typography.sizes)
  .map(([name, value]) => `- **${name}** → \`${value}\``)
  .join('\n')}

### Font Weights

${Object.entries(ds.tokens.typography.weights)
  .map(([name, value]) => `- **${name}** → \`${value}\``)
  .join('\n')}

## Spacing System

${Object.entries(ds.tokens.spacing.padding)
  .map(([name, value]) => `- **${name}** → \`${value}\``)
  .join('\n')}

## Layout Tokens

### Border Radius

${Object.entries(ds.tokens.layout.borderRadius)
  .map(([name, value]) => `- **${name}** → \`${value}\``)
  .join('\n')}

---

**Stats**: ${ds.stats.colorTokens} color tokens, ${ds.stats.typographyTokens} typography tokens, ${ds.stats.components} components
`;

  return { name: 'ui-style-guide.md', content, type: 'markdown' };
}

function generateComponentsDoc(ds: DesignSystem): OutputFile {
  const content = `# UI Components

## Component Library

Total Components: ${ds.components.length}

${ds.components.map(comp => `
### ${comp.name}

**Type**: ${comp.type}
**Variants**: ${comp.variants.join(', ')}
**States**: ${comp.states.join(', ')}

**Composition**: ${comp.composition}

**Tokens Used**:
${comp.tokens.map(t => `- ${t}`).join('\n')}
`).join('\n---\n')}
`;

  return { name: 'ui-components.md', content, type: 'markdown' };
}

function generateScreenReference(results: ImageResult[]): OutputFile {
  const content = `# Screen Reference

${results.map(screen => `
## ${screen.screenName}

**ID**: \`${screen.id}\`
**Category**: ${screen.category}
**Type**: ${screen.metadata.type}
**File**: \`${screen.filename}\`

### Primary Intent
${screen.metadata.primaryIntent}

### Components Used
${screen.components.map(c => `- ${c.name} (${c.type})`).join('\n')}

### UX Patterns
${screen.uxPatterns.map(p => `- **${p.name}**: ${p.description}`).join('\n')}
`).join('\n---\n')}
`;

  return { name: 'screen-reference.md', content, type: 'markdown' };
}

function generateAccessibilityDoc(ds: DesignSystem): OutputFile {
  const content = `# Accessibility Tokens

## Contrast Ratios

${Object.entries(ds.tokens.accessibility.contrast)
  .map(([name, ratio]) => `- **${name}** → ${ratio} ${ratio >= '4.5:1' ? '✅' : '⚠️'}`)
  .join('\n')}

## Tap Targets

${Object.entries(ds.tokens.accessibility.tapTargets)
  .map(([name, size]) => `- **${name}** → ${size}`)
  .join('\n')}

## WCAG Compliance

- ✅ AA Contrast Compliance
- ✅ Touch Target Size Compliance
- ✅ Focus Indicators Present
`;

  return { name: 'accessibility-tokens.md', content, type: 'markdown' };
}

function generateProgressTracker(results: ImageResult[]): OutputFile {
  const completed = results.length;
  const total = 48; // Known total
  const percentage = Math.round((completed / total) * 100);

  const content = `# Progress Tracker

## Summary

| Status | Count | Percentage |
|--------|-------|------------|
| ✅ Completed | ${completed} / ${total} | ${percentage}% |

**Progress**: ${'█'.repeat(Math.floor(percentage / 5))}${'░'.repeat(20 - Math.floor(percentage / 5))} ${percentage}%

## Processed Images

${results.map((r, i) => `${i + 1}. ✅ ${r.filename} → ${r.screenName}`).join('\n')}
`;

  return { name: 'ui-kit-progress-tracker.md', content, type: 'markdown' };
}

function generateTokensJSON(ds: DesignSystem): OutputFile {
  const content = JSON.stringify(ds, null, 2);
  return { name: 'design-tokens.json', content, type: 'json' };
}

function generateCSSVariables(ds: DesignSystem): OutputFile {
  let css = ':root {\n';

  // Colors
  Object.entries(ds.tokens.colors.primitive).forEach(([name, value]) => {
    css += `  --color-${name}: ${value};\n`;
  });

  // Typography
  Object.entries(ds.tokens.typography.sizes).forEach(([name, value]) => {
    css += `  --font-size-${name}: ${value};\n`;
  });

  // Spacing
  Object.entries(ds.tokens.spacing.padding).forEach(([name, value]) => {
    css += `  --spacing-${name}: ${value};\n`;
  });

  css += '}\n';

  return { name: 'tokens.css', content: css, type: 'css' };
}

function generateTailwindConfig(ds: DesignSystem): OutputFile {
  const config = {
    theme: {
      extend: {
        colors: ds.tokens.colors.primitive,
        fontSize: ds.tokens.typography.sizes,
        spacing: ds.tokens.spacing.padding
      }
    }
  };

  const content = `module.exports = ${JSON.stringify(config, null, 2)};\n`;
  return { name: 'tailwind.config.js', content, type: 'javascript' };
}

