export interface ValidationResult {
  isValid: boolean;
  warnings: string[];
  errors: string[];
}

/**
 * Validate extracted tokens for consistency and completeness
 */
export function validateResults(
  designSystem: DesignSystem,
  imageResults: ImageResult[]
): ValidationResult {
  const warnings: string[] = [];
  const errors: string[] = [];

  // Check for minimum color tokens
  if (Object.keys(designSystem.tokens.colors.primitive).length < 5) {
    warnings.push('Less than 5 color tokens found - may be incomplete');
  }

  // Check for typography tokens
  if (Object.keys(designSystem.tokens.typography.sizes).length === 0) {
    errors.push('No typography tokens found');
  }

  // Check for components
  if (designSystem.components.length === 0) {
    warnings.push('No reusable components identified');
  }

  // Check for accessibility
  const contrastRatios = Object.values(designSystem.tokens.accessibility.contrast);
  if (contrastRatios.length === 0) {
    warnings.push('No accessibility contrast ratios calculated');
  }

  return {
    isValid: errors.length === 0,
    warnings,
    errors
  };
}

